// Pets catalog — browse every first-generation pet with art, stats, and talents.
// (Catalog data is generated by scripts/pets/*.py into site/data/pets/pets.json.)
import { esc } from './display.js';

const $ = (id) => document.getElementById(id);
let PETS = null;

export async function renderPets() {
  const body = $('petsBody');
  if (!body) return;
  if (!PETS) {
    body.innerHTML = '<div class="pets-loading">Loading pet catalog…</div>';
    try { PETS = await (await fetch('./data/pets/pets.json')).json(); }
    catch { PETS = []; }
  }
  body.innerHTML = `<div class="pets-hero"><h1 class="gallery-title">Pets</h1>
    <p class="gallery-lede">The pet catalog is being assembled.</p></div>
    <p class="g-empty">${PETS.length ? `${PETS.length} pets loaded.` : 'Catalog coming soon.'}</p>`;
}
